    "pro.table.row1.free": "1 source",
    "pro.table.row2": "Create Blank Playlist",
    "pro.table.row2.free": "1 playlist",
    "pro.table.row8": "Xtream Code Import",
    "pro.table.row3": "Local IPTV Server",
    "pro.table.row4": "All Export Formats",
